# Code to capture website screenshot using headless Chrome
from selenium import webdriver
from selenium.webdriver.chrome.options import Options
import boto3

def capture_screenshot(url, output_file):
    chrome_options = Options()
    chrome_options.add_argument("--headless")
    chrome_options.add_argument("--disable-gpu")

    driver = webdriver.Chrome(options=chrome_options)
    driver.get(url)
    driver.save_screenshot(output_file)
    driver.quit()

def upload_to_s3(file_path, bucket_name, object_name):
    s3 = boto3.client('s3')
    s3.upload_file(file_path, bucket_name, object_name)

url = 'https://www.example.com'
output_file = 'screenshot.png'
s3_bucket_name = 'your-s3-bucket-name'
s3_object_name = 'screenshot.png'

capture_screenshot(url, output_file)
upload_to_s3(output_file, s3_bucket_name, s3_object_name)